# Total prompt count for progress reporting
TOTAL_PROMPTS = sum(len(v) for v in GRADED_PROMPTS.values())


async def test_classification_http(endpoint: str):
    """Test classification via HTTP POST to /solve with dry-run detection."""
    import httpx

    results = defaultdict(lambda: {"total": 0, "pass": 0, "fail": 0, "misclass": []})
    tested = 0

    async with httpx.AsyncClient(timeout=30.0) as client:
        for expected_type, prompts in sorted(GRADED_PROMPTS.items()):
            for p in prompts:
                tested += 1
                prompt_text = p["prompt"]
                try:
                    resp = await client.post(
                        f"{endpoint}/solve",
                        json={
                            "prompt": prompt_text,
                            "tripletex_credentials": {
                                "base_url": "https://tx-proxy.ainm.no/v2",
                                "session_token": "dry-run-no-token",
                            },
                        },
                    )
                    body = resp.json()
                    got_type = body.get("task_type", "UNKNOWN")
                    got_norm = got_type.replace("TaskType.", "").upper()
                    exp_norm = expected_type.upper()
                    aliases = {
                        "CREATE_SUPPLIER_INVOICE": "REGISTER_SUPPLIER_INVOICE",
                        "INVOICE_EXISTING_CUSTOMER": "CREATE_INVOICE",
                    }
                    got_cmp = aliases.get(got_norm, got_norm)
                    exp_cmp = aliases.get(exp_norm, exp_norm)

                    results[expected_type]["total"] += 1
                    if got_cmp == exp_cmp:
                        results[expected_type]["pass"] += 1
                    else:
                        results[expected_type]["fail"] += 1
                        results[expected_type]["misclass"].append(
                            (prompt_text[:80], got_type)
                        )
                except Exception as e:
                    results[expected_type]["total"] += 1
                    results[expected_type]["fail"] += 1
                    results[expected_type]["misclass"].append(
                        (prompt_text[:80], f"ERROR: {e}")
                    )

                if tested % 100 == 0:
                    print(f"  Progress: {tested}/{TOTAL_PROMPTS}...", flush=True)

    return results


async def test_classification_local():
    """Test classification by importing classifier directly (fastest)."""
    sys.path.insert(0, ".")
    from main import classify

    results = defaultdict(lambda: {"total": 0, "pass": 0, "fail": 0, "misclass": []})
    tested = 0

    for expected_type, prompts in sorted(GRADED_PROMPTS.items()):
        for p in prompts:
            tested += 1
            prompt_text = p["prompt"]
            try:
                r = await classify(prompt_text)
                if isinstance(r, list):
                    got_type = r[0].task_type.value if r else "unknown"
                else:
                    got_type = r.task_type.value
                got_norm = got_type.upper()
                exp_norm = expected_type.upper()
                aliases = {
                    "CREATE_SUPPLIER_INVOICE": "REGISTER_SUPPLIER_INVOICE",
                    "INVOICE_EXISTING_CUSTOMER": "CREATE_INVOICE",
                }
                got_cmp = aliases.get(got_norm, got_norm)
                exp_cmp = aliases.get(exp_norm, exp_norm)

                results[expected_type]["total"] += 1
                if got_cmp == exp_cmp:
                    results[expected_type]["pass"] += 1
                else:
                    results[expected_type]["fail"] += 1
                    results[expected_type]["misclass"].append(
                        (prompt_text[:80], got_type)
                    )
            except Exception as e:
                results[expected_type]["total"] += 1
                results[expected_type]["fail"] += 1
                results[expected_type]["misclass"].append(
                    (prompt_text[:80], f"ERROR: {e}")
                )

            if tested % 200 == 0:
                print(f"  Progress: {tested}/{TOTAL_PROMPTS}...", flush=True)

    return results


def print_summary(results: dict, elapsed: float):
    """Print summary table."""
    print("\n" + "=" * 90)
    print(f"{'Task Type':<35} {'Total':>6} {'Pass':>6} {'Fail':>6} {'Rate':>7}")
    print("-" * 90)

    total_all = pass_all = fail_all = 0
    for task_type in sorted(results.keys()):
        r = results[task_type]
        total_all += r["total"]
        pass_all += r["pass"]
        fail_all += r["fail"]
        rate = f"{100 * r['pass'] / r['total']:.0f}%" if r["total"] else "N/A"
        marker = " ***" if r["fail"] > 0 else ""
        print(f"  {task_type:<33} {r['total']:>6} {r['pass']:>6} {r['fail']:>6} {rate:>7}{marker}")

    print("-" * 90)
    rate = f"{100 * pass_all / total_all:.1f}%" if total_all else "N/A"
    print(f"  {'TOTAL':<33} {total_all:>6} {pass_all:>6} {fail_all:>6} {rate:>7}")
    print(f"\nElapsed: {elapsed:.1f}s")

    all_misclass = []
    for task_type, r in sorted(results.items()):
        for prompt_snip, got in r["misclass"]:
            all_misclass.append((task_type, got, prompt_snip))

    if all_misclass:
        print(f"\n{'='*90}")
        print(f"MISCLASSIFICATIONS ({len(all_misclass)}):")
        print(f"{'-'*90}")
        for expected, got, snip in all_misclass[:50]:
            print(f"  Expected: {expected:<30} Got: {got}")
            print(f"    Prompt: {snip}")
        if len(all_misclass) > 50:
            print(f"  ... and {len(all_misclass) - 50} more")


def main():
    parser = argparse.ArgumentParser(description="Classification regression tests from grader logs")
    parser.add_argument("--endpoint", default="http://localhost:8080",
                        help="Service endpoint (default: http://localhost:8080)")
    parser.add_argument("--local", action="store_true",
                        help="Import classifier directly instead of HTTP")
    args = parser.parse_args()

    print(f"Classification regression test: {TOTAL_PROMPTS} prompts across {len(GRADED_PROMPTS)} task types")

    t0 = time.time()
    if args.local:
        print("Mode: local import (no HTTP)")
        results = asyncio.run(test_classification_local())
    else:
        print(f"Mode: HTTP to {args.endpoint}")
        results = asyncio.run(test_classification_http(args.endpoint))
    elapsed = time.time() - t0

    print_summary(results, elapsed)

    total_fail = sum(r["fail"] for r in results.values())
    sys.exit(1 if total_fail > 0 else 0)


if __name__ == "__main__":
    main()
